var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"문득, 떠올리곤 한다.","JPN":"ふと、思い出すことがある。","ENG":"Sometimes, old memories come up.","TWN":"總是會突然想起。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"돌이켜 보면, 기억 속 할아버님께서는 늘 혼자셨다.","JPN":"思い返せば、記憶の中のお祖父様はいつも一人だった。","ENG":"In my memory, my grandfather was always alone.","TWN":"回想起來，在我的記憶裡，爺爺總是自己一個人。"},"stage":{"bg":"ALPHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"알파트릭스의 총수로서 누구보다 높은 곳에 서 계셨을 때도.","JPN":"アルファトリックスの総帥として誰よりも高い地位にいた時も。","ENG":"When he was the president of Alphatrix.","TWN":"無論是身為阿爾法崔克斯的會長時期，位居於高位時，"},"stage":{"bg":"ALPHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"스물네 시간, 다른 사람의 간호가 필요할 정도로 병세가 깊어지셨을 때도.","JPN":"24時間、誰かの看護が必要になるほど病気が酷くなった時も。","ENG":"When he became too sick and couldn’t take care of himself.","TWN":"或是病重到需要有人24小時照顧時，"},"stage":{"bg":"ALPHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"……할아버님께서는, 늘 혼자였다.","JPN":"……お祖父様は、いつも一人だった。","ENG":"He was always alone.","TWN":"……爺爺總是自己一個人。"},"stage":{"bg":"ALPHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"…그래서 결정하셨나요, 아버지?","JPN":"それで……答えは出たのですか？　父さん。","ENG":"Did you make up your mind, father?","TWN":"…爸，決定好了嗎？"},"stage":{"bg":"ALPHA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"분명 오늘까지 결정해달라고 부탁드렸을 텐데요?","JPN":"今日までに決めてほしいとお願いしたはずです。","ENG":"You were told to make the decision by today.","TWN":"我不是拜託爸今天一定要有結果嗎？"},"stage":{"bg":"ALPHA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ALPHA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"일 없다. 다들 나가 봐라.","JPN":"くだらん。みな出ていけ。","ENG":"I don’t care. Leave me alone. All of you.","TWN":"沒有，都給我出去。"},"stage":{"bg":"ALPHA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"아버님! 다시 한 번 생각해 주세요!","JPN":"お父様！　考え直してください。","ENG":"Father, please reconsider!","TWN":"爸！我拜託你再想一想！"},"stage":{"bg":"ALPHA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"저희가 아버님 밑에서 해드린 게 얼만데요!","JPN":"私たちがお父様の下でどれだけ頑張ったと思ってるんですか！","ENG":"We worked so hard for you!","TWN":"我們在爸底下為爸做多少事！"},"stage":{"bg":"ALPHA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"적어도 독점 채굴 좌표 한두 군데는 넘겨주실 수 있잖아요!","JPN":"せめて独占採掘座標の一つや二つくらい、渡してくれてもいいでしょう！","ENG":"You could at least give us some of the exclusive mining coordinates!","TWN":"起碼要給我們1、2個獨佔的開採座標吧？！"},"stage":{"bg":"ALPHA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"…무슨 개소리야!","JPN":"……バカを言うな！","ENG":"What?","TWN":"…你在說什麼鬼話！"},"stage":{"bg":"ALPHA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"네놈들이 뭘 했다고 그걸 가져간다는 거야?","JPN":"お前らになんの権利があるんだ！","ENG":"You don’t deserve it!","TWN":"你們憑什麼拿走那些？"},"stage":{"bg":"ALPHA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"오라버니는 좀 빠지시죠, 자식새끼라고는 자기 닮은 망나니밖에 없으면서.","JPN":"お兄様は黙っていてください。子どもだって自分に似たならず者しかいないんだから。","ENG":"Jaehyuk, step aside. Your only son is a jerk like you.","TWN":"大哥你退下吧，說好聽點是一家人，說難聽點這種行為跟流氓有什麼兩樣！"},"stage":{"bg":"ALPHA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐야!?","JPN":"なんだと！？","ENG":"What did you say?!","TWN":"你說什麼？！"},"stage":{"bg":"ALPHA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"……시끄럽다. 다들 나가라고 말했을 텐데.","JPN":"……うるさいぞ。出て行けと言ったはずだ。","ENG":"Shut up. I told you to leave.","TWN":"……都給我住口，叫你們出去沒聽到嗎！"},"stage":{"bg":"ALPHA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"쳇…….","JPN":"ちっ……","ENG":"*Tst*","TWN":"嗟……"},"stage":{"bg":"ALPHA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"당신이라는 사람은 책임감이라고는 눈곱만큼도 없군요, 아버지.","JPN":"あんたという人は責任感の欠片もないのですね、父さん。","ENG":"You’re a very irresponsible man.","TWN":"爸，像你這種人，一點責任感也沒有！"},"stage":{"bg":"ALPHA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ALPHA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"그 땐 그럴 수밖에 없었다.","JPN":"あの時はそうするしかなかった。","ENG":"I couldn’t help it back then.","TWN":"我那時候是有苦衷的。"},"stage":{"bg":"ALPHA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"그럴 수밖에 없었다고요?","JPN":"そうするしかなかった？","ENG":"You couldn't help it?","TWN":"苦衷？"},"stage":{"bg":"ALPHA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"그래, 그럴 수밖에 없었겠지. 당신은 돈에 미친 인간이니까.","JPN":"まあ、そうだろうな。あんたは金しか知らない人間だから。","ENG":"Of course. You are crazy about money.","TWN":"對啊，當然是有苦衷囉，苦衷就是你眼裡只有錢！"},"stage":{"bg":"ALPHA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ALPHA_03","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};